// Script Continued Below
function onLoad() {

	var state = (g_form.isNewRecord()) ? "New" : g_form.getValue("state");

	if (state == "New"){
		var taskPermissions = JSON.parse(g_scratchpad.taskPermissions);
		taskPermissions.isSubTask;
		if(taskPermissions.isSubTask){		
			var task_owner = (g_scratchpad.parentTaskAssignedMember + '' != '') ? g_scratchpad.parentTaskAssignedMember : g_scratchpad.parentTaskOwner;
			g_form.setValue('u_task_requester', task_owner);
		}

	} 
}
